commit 6f6a0eb6bb6c1b4b11f8a7bd37b714f68f6f5f15
Author: Josh Law <objecting@objecting.org>
Date:   Wed Mar 25 07:38:00 2026 +0000

    mm/damon/core: move last_nr_regions from static local to damon_ctx

    kdamond_split_regions() uses a function-level static variable to
    remember the previous iteration's region count.  This is shared across
    all kdamond threads, so one kdamond's region count leaks into another's
    splitting decision.  Move the variable into struct damon_ctx so each
    kdamond tracks its own state.

    Signed-off-by: Josh Law <objecting@objecting.org>

diff --git a/include/linux/damon.h b/include/linux/damon.h
index d9a3babbafc1..0dc68257f004 100644
--- a/include/linux/damon.h
+++ b/include/linux/damon.h
@@ -815,6 +815,8 @@ struct damon_ctx {
 	struct completion kdamond_started;
 	/* for scheme quotas prioritization */
 	unsigned long *regions_score_histogram;
+	/* for kdamond_split_regions() heuristic */
+	unsigned int last_nr_regions;

 	/* lists of &struct damon_call_control */
 	struct list_head call_controls;
diff --git a/mm/damon/core.c b/mm/damon/core.c
index 691997b44551..b9615df921c3 100644
--- a/mm/damon/core.c
+++ b/mm/damon/core.c
@@ -2743,7 +2743,6 @@ static void kdamond_split_regions(struct damon_ctx *ctx)
 {
 	struct damon_target *t;
 	unsigned int nr_regions = 0;
-	static unsigned int last_nr_regions;
 	int nr_subregions = 2;

 	damon_for_each_target(t, ctx)
@@ -2753,14 +2752,14 @@ static void kdamond_split_regions(struct damon_ctx *ctx)
 		return;

 	/* Maybe the middle of the region has different access frequency */
-	if (last_nr_regions == nr_regions &&
+	if (ctx->last_nr_regions == nr_regions &&
 			nr_regions < ctx->attrs.max_nr_regions / 3)
 		nr_subregions = 3;

 	damon_for_each_target(t, ctx)
 		damon_split_regions_of(t, nr_subregions, ctx->min_region_sz);

-	last_nr_regions = nr_regions;
+	ctx->last_nr_regions = nr_regions;
 }

